use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract information from a PDF file
sub extract_info {
    my ($pdf_file) = @_;
    my $api = PDF::API2->open($pdf_file);

    my $info = $api->info;
    my $author = $info->get('Author') || 'Unknown';
    my $title = $info->get('Title') || 'Unknown';
    my $creation_date = $info->get('CreationDate') || 'Unknown';

    return {
        author => $author,
        title => $title,
        creation_date => $creation_date
    };
}

# Function to print the extracted information
sub print_info {
    my ($info) = @_;
    print "Author: $info->{author}\n";
    print "Title: $info->{title}\n";
    print "Creation Date: $info->{creation_date}\n";
}

# Main script
my $pdf_file = $ARGV[0] || 'example.pdf';

# Extract information from the PDF file
my $info = extract_info($pdf_file);

# Print the extracted information
print_info($info);
